MQTT_NONREASONING = [
    {"q": "What is a retained message in MQTT?", "a": "A retained message is stored by the MQTT broker and sent immediately to any new subscriber of that topic. Set using the retain flag when publishing, useful for current state like device status."},
    {"q": "What is the difference between QoS 0 and QoS 1?", "a": "QoS 0 (at most once) sends without confirmation - may be lost. QoS 1 (at least once) requires PUBACK acknowledgment, retrying until confirmed - guaranteed but may arrive multiple times."},
    {"q": "What is an MQTT broker?", "a": "An MQTT broker is a server that receives messages from publishers and routes them to subscribers based on topics. Popular brokers: Mosquitto, HiveMQ, EMQX, AWS IoT Core, Azure IoT Hub."},
    {"q": "What is the MQTT keep-alive interval?", "a": "Keep-alive is the maximum time between messages before disconnection. Default 60 seconds. Clients send PINGREQ if idle; broker responds with PINGRESP. Lower = faster detection, higher = battery savings."},
    {"q": "What is a clean session in MQTT?", "a": "Clean session (true) discards previous session data. When false, broker remembers subscriptions and queues QoS 1/2 messages sent while disconnected. Use false for reliable delivery."},
    {"q": "What MQTT library should I use for ESP32?", "a": "PubSubClient for simple use cases. AsyncMqttClient for advanced features (QoS 2, async). For AWS IoT, use AWS IoT SDK. All work with WiFiClientSecure for TLS."},
    {"q": "What is MQTT topic structure best practice?", "a": "Use hierarchical structure: location/device/measurement (e.g., home/livingroom/temperature). Lowercase, hyphens, no leading /. Keep short for IoT devices."},
    {"q": "How large can an MQTT message be?", "a": "Protocol allows 256MB, but practical limits are 1-10MB. For IoT, keep under 1KB. ESP32 PubSubClient defaults to 256 bytes (configurable via MQTT_MAX_PACKET_SIZE)."},
    {"q": "What is MQTT 5.0?", "a": "MQTT 5.0 adds: message expiry, topic aliases, user properties, shared subscriptions, enhanced auth, and reason codes. Better for modern IoT but requires compatible broker and client."},
    {"q": "What is the default MQTT port?", "a": "1883 for unencrypted connections, 8883 for TLS/SSL encrypted connections. WebSocket MQTT typically uses 8083 (ws) or 8084 (wss)."},
    {"q": "What is MQTT message expiry?", "a": "MQTT 5.0 feature that sets a lifetime for messages. Broker discards expired messages instead of delivering stale data. Useful for time-sensitive sensor readings."},
    {"q": "What is an MQTT topic alias?", "a": "MQTT 5.0 feature that replaces long topic strings with short integers after initial mapping. Reduces bandwidth for repeated publishes to same topic."},
    {"q": "How do I debug MQTT connections?", "a": "Use MQTT Explorer or mqtt-spy GUI tools. Check client.state() return code. Enable Serial debug output. Monitor broker logs. Test with mosquitto_pub/sub CLI tools."},
    {"q": "What is MQTT over WebSocket?", "a": "MQTT transported over WebSocket protocol, enabling browser-based MQTT clients. Uses ports 8083/8084. Libraries: MQTT.js, Eclipse Paho. Useful for web dashboards."},
    {"q": "What is shared subscription in MQTT?", "a": "MQTT 5.0 feature where multiple subscribers share message load on a topic (round-robin). Format: $share/group/topic. Useful for scalable message processing."},
]

