ARDUINO_REASONING = [
    {"q": "How do I use interrupts for button debouncing?", "a": "<|thinking|>\nButton debouncing with interrupts:\n1. Hardware interrupt on pin change\n2. Software debounce timer\n3. Volatile variables for ISR\n4. Minimal ISR code\n<|/thinking|>\n\n```cpp\nconst int BUTTON_PIN = 2;\nconst unsigned long DEBOUNCE = 50;\n\nvolatile bool pressed = false;\nvolatile unsigned long lastInterrupt = 0;\n\nvoid IRAM_ATTR buttonISR() {\n  unsigned long now = millis();\n  if (now - lastInterrupt > DEBOUNCE) {\n    pressed = true;\n    lastInterrupt = now;\n  }\n}\n\nvoid setup() {\n  pinMode(BUTTON_PIN, INPUT_PULLUP);\n  attachInterrupt(digitalPinToInterrupt(BUTTON_PIN), buttonISR, FALLING);\n}\n\nvoid loop() {\n  if (pressed) {\n    pressed = false;\n    Serial.println(\"Button pressed!\");\n    digitalWrite(LED_PIN, !digitalRead(LED_PIN));\n  }\n}\n```"},
    {"q": "How do I read multiple analog sensors efficiently on ESP32?", "a": "<|thinking|>\nEfficient multi-sensor ADC on ESP32:\n1. Use ADC1 (ADC2 conflicts with WiFi)\n2. Set attenuation for voltage range\n3. Average readings for noise\n4. Use calibration for accuracy\n<|/thinking|>\n\n```cpp\n#include <esp_adc_cal.h>\n\nconst adc1_channel_t channels[] = {\n  ADC1_CHANNEL_0, ADC1_CHANNEL_3,  // GPIO36, GPIO39\n  ADC1_CHANNEL_6, ADC1_CHANNEL_7   // GPIO34, GPIO35\n};\nesp_adc_cal_characteristics_t adc_chars;\n\nvoid setup() {\n  adc1_config_width(ADC_WIDTH_BIT_12);\n  for (auto ch : channels)\n    adc1_config_channel_atten(ch, ADC_ATTEN_DB_11);\n  esp_adc_cal_characterize(ADC_UNIT_1, ADC_ATTEN_DB_11,\n                           ADC_WIDTH_BIT_12, 1100, &adc_chars);\n}\n\nuint32_t readAvg(adc1_channel_t ch, int samples = 10) {\n  uint32_t sum = 0;\n  for (int i = 0; i < samples; i++)\n    sum += adc1_get_raw(ch);\n  return esp_adc_cal_raw_to_voltage(sum / samples, &adc_chars);\n}\n```"},
    {"q": "How do I implement a watchdog timer on ESP32?", "a": "<|thinking|>\nWatchdog timer (WDT):\n1. Resets if not fed\n2. Prevents hangs\n3. Essential for remote IoT\n4. Feed in main loop\n<|/thinking|>\n\n```cpp\n#include <esp_task_wdt.h>\n\n#define WDT_TIMEOUT 10  // Seconds\n\nvoid setup() {\n  esp_task_wdt_init(WDT_TIMEOUT, true);  // true = panic on timeout\n  esp_task_wdt_add(NULL);  // Add current task\n}\n\nvoid loop() {\n  esp_task_wdt_reset();  // Feed watchdog\n  \n  doSensorReading();\n  doNetworkStuff();\n  \n  delay(1000);\n}\n\nvoid longOperation() {\n  for (int i = 0; i < 1000; i++) {\n    // Long work...\n    if (i % 100 == 0) esp_task_wdt_reset();  // Feed during long loops\n  }\n}\n```\n\nIf loop() blocks > 10 seconds, ESP32 resets automatically."},
    {"q": "How do I implement OTA updates on ESP8266?", "a": "<|thinking|>\nOTA (Over-The-Air) updates:\n1. ArduinoOTA library\n2. WiFi connectivity\n3. Optional authentication\n4. Progress callbacks\n<|/thinking|>\n\n```cpp\n#include <ESP8266WiFi.h>\n#include <ArduinoOTA.h>\n\nvoid setup() {\n  WiFi.begin(ssid, password);\n  while (WiFi.status() != WL_CONNECTED) delay(500);\n  \n  ArduinoOTA.setHostname(\"esp-sensor\");\n  ArduinoOTA.setPassword(\"admin\");\n  \n  ArduinoOTA.onStart([]() {\n    Serial.println(\"OTA starting...\");\n  });\n  ArduinoOTA.onProgress([](unsigned int progress, unsigned int total) {\n    Serial.printf(\"Progress: %u%%\\r\", (progress * 100) / total);\n  });\n  ArduinoOTA.onEnd([]() {\n    Serial.println(\"\\nOTA complete!\");\n  });\n  \n  ArduinoOTA.begin();\n}\n\nvoid loop() {\n  ArduinoOTA.handle();  // Must be called regularly\n  // Your code...\n}\n```\n\nUpload: Arduino IDE > Tools > Port > Network ports"},
    {"q": "How do I implement deep sleep with sensor wake on ESP32?", "a": "<|thinking|>\nESP32 deep sleep + sensor wake:\n1. Timer wake for periodic readings\n2. GPIO wake for motion/events\n3. RTC memory preserves data\n4. ~10µA sleep current\n<|/thinking|>\n\n```cpp\n#define uS_TO_S 1000000\n#define SLEEP_TIME 300  // 5 minutes\n#define MOTION_PIN GPIO_NUM_33\n\nRTC_DATA_ATTR int bootCount = 0;  // Survives deep sleep\n\nvoid setup() {\n  bootCount++;\n  Serial.printf(\"Boot #%d\\n\", bootCount);\n  \n  esp_sleep_wakeup_cause_t cause = esp_sleep_get_wakeup_cause();\n  if (cause == ESP_SLEEP_WAKEUP_EXT0) {\n    Serial.println(\"Motion detected!\");\n    handleMotion();\n  } else {\n    Serial.println(\"Timer wake\");\n    readAndSendSensors();\n  }\n  \n  // Configure wake sources\n  esp_sleep_enable_timer_wakeup(SLEEP_TIME * uS_TO_S);\n  esp_sleep_enable_ext0_wakeup(MOTION_PIN, HIGH);  // Wake on HIGH\n  \n  esp_deep_sleep_start();\n}\n\nvoid loop() {}  // Never reached\n```"},
    {"q": "How do I read DHT22 temperature and humidity sensor?", "a": "<|thinking|>\nDHT22 reading:\n1. DHT library\n2. 2-second minimum interval\n3. Error handling for failed reads\n4. Proper pin configuration\n<|/thinking|>\n\n```cpp\n#include \"DHT.h\"\n\n#define DHTPIN 4\n#define DHTTYPE DHT22\n\nDHT dht(DHTPIN, DHTTYPE);\n\nvoid setup() {\n  Serial.begin(115200);\n  dht.begin();\n}\n\nvoid loop() {\n  float temp = dht.readTemperature();\n  float humidity = dht.readHumidity();\n  \n  if (isnan(temp) || isnan(humidity)) {\n    Serial.println(\"DHT read failed!\");\n    return;\n  }\n  \n  float heatIndex = dht.computeHeatIndex(temp, humidity, false);\n  \n  Serial.printf(\"Temp: %.1f°C, Humidity: %.1f%%, Heat Index: %.1f°C\\n\",\n                temp, humidity, heatIndex);\n  \n  delay(2000);  // DHT22 needs 2s between reads\n}\n```"},
    {"q": "How do I use SPIFFS for file storage on ESP32?", "a": "<|thinking|>\nSPIFFS file storage:\n1. Initialize filesystem\n2. Read/write files\n3. Good for config, logs\n4. Limited write cycles\n<|/thinking|>\n\n```cpp\n#include <SPIFFS.h>\n\nvoid setup() {\n  if (!SPIFFS.begin(true)) {  // true = format if failed\n    Serial.println(\"SPIFFS failed!\");\n    return;\n  }\n  \n  // Write config\n  File file = SPIFFS.open(\"/config.txt\", \"w\");\n  file.println(\"ssid=MyNetwork\");\n  file.println(\"password=secret\");\n  file.close();\n  \n  // Read config\n  file = SPIFFS.open(\"/config.txt\", \"r\");\n  while (file.available()) {\n    String line = file.readStringUntil('\\n');\n    Serial.println(line);\n  }\n  file.close();\n  \n  // Check space\n  Serial.printf(\"Used: %d / %d bytes\\n\",\n                SPIFFS.usedBytes(), SPIFFS.totalBytes());\n}\n```"},
    {"q": "How do I implement a web server on ESP32?", "a": "<|thinking|>\nESP32 web server:\n1. WiFi in station or AP mode\n2. Handle HTTP requests\n3. Serve HTML/JSON\n4. Handle forms/API calls\n<|/thinking|>\n\n```cpp\n#include <WiFi.h>\n#include <WebServer.h>\n\nWebServer server(80);\n\nvoid handleRoot() {\n  String html = \"<h1>ESP32 Sensor</h1>\";\n  html += \"<p>Temperature: \" + String(readTemp()) + \"°C</p>\";\n  html += \"<form action='/led' method='POST'>\";\n  html += \"<button name='state' value='on'>LED ON</button>\";\n  html += \"<button name='state' value='off'>LED OFF</button>\";\n  html += \"</form>\";\n  server.send(200, \"text/html\", html);\n}\n\nvoid handleLED() {\n  String state = server.arg(\"state\");\n  digitalWrite(LED_PIN, state == \"on\" ? HIGH : LOW);\n  server.sendHeader(\"Location\", \"/\");\n  server.send(303);\n}\n\nvoid handleAPI() {\n  String json = \"{\\\"temp\\\":\" + String(readTemp()) + \"}\";\n  server.send(200, \"application/json\", json);\n}\n\nvoid setup() {\n  WiFi.begin(ssid, password);\n  server.on(\"/\", handleRoot);\n  server.on(\"/led\", HTTP_POST, handleLED);\n  server.on(\"/api/sensor\", handleAPI);\n  server.begin();\n}\n\nvoid loop() { server.handleClient(); }\n```"},
    {"q": "How do I use the ESP32 hardware timer for precise timing?", "a": "<|thinking|>\nESP32 hardware timer:\n1. Microsecond precision\n2. Interrupt-based\n3. Four timers available\n4. Non-blocking\n<|/thinking|>\n\n```cpp\nhw_timer_t* timer = NULL;\nvolatile int counter = 0;\n\nvoid IRAM_ATTR onTimer() {\n  counter++;\n}\n\nvoid setup() {\n  Serial.begin(115200);\n  \n  // Timer 0, divider 80 (1MHz tick), count up\n  timer = timerBegin(0, 80, true);\n  \n  // Attach interrupt\n  timerAttachInterrupt(timer, &onTimer, true);\n  \n  // Set alarm for 1 second (1,000,000 µs)\n  timerAlarmWrite(timer, 1000000, true);  // true = auto-reload\n  timerAlarmEnable(timer);\n}\n\nvoid loop() {\n  Serial.printf(\"Counter: %d\\n\", counter);\n  delay(5000);\n}\n```\n\nTimer fires exactly every 1 second regardless of loop() time."},
    {"q": "How do I save settings to NVS (Non-Volatile Storage) on ESP32?", "a": "<|thinking|>\nNVS for settings:\n1. Key-value storage\n2. Survives reboots\n3. Better than SPIFFS for small data\n4. Wear leveling built-in\n<|/thinking|>\n\n```cpp\n#include <Preferences.h>\n\nPreferences prefs;\n\nvoid setup() {\n  Serial.begin(115200);\n  \n  prefs.begin(\"settings\", false);  // false = read-write\n  \n  // Read or use defaults\n  String ssid = prefs.getString(\"ssid\", \"default_ssid\");\n  int threshold = prefs.getInt(\"threshold\", 100);\n  bool enabled = prefs.getBool(\"enabled\", true);\n  \n  Serial.printf(\"SSID: %s, Threshold: %d, Enabled: %d\\n\",\n                ssid.c_str(), threshold, enabled);\n  \n  // Save new settings\n  prefs.putString(\"ssid\", \"NewNetwork\");\n  prefs.putInt(\"threshold\", 150);\n  prefs.putBool(\"enabled\", false);\n  \n  prefs.end();\n}\n```"},
]

ARDUINO_NONREASONING = [
    {"q": "What is the maximum clock speed of ESP32?", "a": "ESP32 runs at 240 MHz by default (dual-core Xtensa LX6). Can be set to 80/160/240 MHz for power savings. Use setCpuFrequencyMhz()."},
    {"q": "How much RAM does ESP32 have?", "a": "520KB SRAM: 320KB DRAM + 200KB IRAM. After WiFi/BT stack, ~200-280KB available. Use ESP.getFreeHeap() to check."},
    {"q": "What is the difference between delay() and millis()?", "a": "delay() blocks execution. millis() returns time since boot for non-blocking timing: if (millis() - lastTime > interval) allows other code to run while waiting."},
    {"q": "What is SPI and when should I use it?", "a": "SPI uses 4 wires (MOSI, MISO, SCK, CS) for fast synchronous communication. Up to 80MHz on ESP32. Use for: SD cards, displays, LoRa, fast sensors. Faster than I2C but more pins."},
    {"q": "What is I2C and when should I use it?", "a": "I2C uses 2 wires (SDA, SCL) with device addressing. Slower than SPI but fewer pins. Use for: sensors, displays, RTCs. Multiple devices on same bus."},
    {"q": "How many GPIO pins does ESP32 have?", "a": "ESP32 has 34 GPIO pins, but not all usable: GPIO6-11 are flash pins, GPIO34-39 are input-only, some have restrictions. ~25 pins typically available."},
    {"q": "What is PWM and how do I use it?", "a": "PWM (Pulse Width Modulation) simulates analog output via rapid HIGH/LOW switching. Use ledcSetup() and ledcWrite() on ESP32, or analogWrite() on Arduino. 8-bit (0-255) resolution."},
    {"q": "What is the difference between INPUT and INPUT_PULLUP?", "a": "INPUT leaves pin floating (needs external resistor). INPUT_PULLUP enables internal ~45kΩ pull-up resistor, defaulting pin to HIGH. Use INPUT_PULLUP for buttons to ground."},
    {"q": "How do I debug Arduino code?", "a": "Use Serial.print() for output. Serial Monitor at correct baud rate. For ESP32: Serial.printf() with format strings. Use LED for basic state indication."},
    {"q": "What is the difference between analogRead() and digitalRead()?", "a": "analogRead() returns ADC value (0-4095 on ESP32, 0-1023 on Arduino) for analog voltage. digitalRead() returns HIGH (1) or LOW (0) for digital state."},
    {"q": "What voltage does ESP32 operate at?", "a": "ESP32 operates at 3.3V logic. DO NOT connect 5V signals directly. Power via USB (5V) or Vin (5-12V), regulator provides 3.3V."},
    {"q": "What is flash memory on ESP32?", "a": "ESP32 typically has 4MB flash for program and data storage. Partitioned for: app, OTA, SPIFFS/LittleFS, NVS. Check with ESP.getFlashChipSize()."},
    {"q": "How do I reset ESP32 programmatically?", "a": "Use ESP.restart() for software reset. For hard reset, use external reset pin or power cycle."},
    {"q": "What is the difference between ESP32 and ESP8266?", "a": "ESP32: Dual-core 240MHz, 520KB RAM, Bluetooth, more GPIO, better ADC. ESP8266: Single-core 80MHz, 80KB RAM, cheaper. ESP32 for new projects."},
    {"q": "How do I put ESP32 in access point mode?", "a": "WiFi.softAP(ssid, password) creates an access point. Devices connect to ESP32's network. Useful for initial configuration without existing WiFi."},
]

