SENSOR_REASONING = [
    {"q": "How do I calibrate a soil moisture sensor?", "a": "<|thinking|>\nSoil moisture calibration:\n1. Read value in dry air (max)\n2. Read value in water (min)\n3. Map to 0-100% range\n4. Account for soil type\n<|/thinking|>\n\n```cpp\nconst int MOISTURE_PIN = 34;\n\n// Calibration values (measure these!)\nconst int AIR_VALUE = 3500;    // Sensor in dry air\nconst int WATER_VALUE = 1500;  // Sensor in water\n\nint readMoisturePercent() {\n  int raw = analogRead(MOISTURE_PIN);\n  \n  // Map and constrain to 0-100%\n  int percent = map(raw, AIR_VALUE, WATER_VALUE, 0, 100);\n  percent = constrain(percent, 0, 100);\n  \n  return percent;\n}\n\nvoid setup() {\n  Serial.begin(115200);\n}\n\nvoid loop() {\n  int moisture = readMoisturePercent();\n  Serial.printf(\"Soil moisture: %d%%\\n\", moisture);\n  \n  if (moisture < 30) {\n    Serial.println(\"Soil is dry - water needed!\");\n  }\n  \n  delay(1000);\n}\n```\n\nCalibrate for your specific soil type for accuracy."},
    {"q": "How do I read a BMP280 pressure/temperature sensor?", "a": "<|thinking|>\nBMP280 reading:\n1. I2C or SPI interface\n2. Adafruit BMP280 library\n3. Provides temp, pressure, altitude\n4. Address 0x76 or 0x77\n<|/thinking|>\n\n```cpp\n#include <Wire.h>\n#include <Adafruit_BMP280.h>\n\nAdafruit_BMP280 bmp;\n\nvoid setup() {\n  Serial.begin(115200);\n  \n  if (!bmp.begin(0x76)) {  // Try 0x77 if not found\n    Serial.println(\"BMP280 not found!\");\n    while (1);\n  }\n  \n  // Configure for weather monitoring\n  bmp.setSampling(Adafruit_BMP280::MODE_NORMAL,\n                  Adafruit_BMP280::SAMPLING_X2,   // temp\n                  Adafruit_BMP280::SAMPLING_X16,  // pressure\n                  Adafruit_BMP280::FILTER_X16,\n                  Adafruit_BMP280::STANDBY_MS_500);\n}\n\nvoid loop() {\n  float temp = bmp.readTemperature();\n  float pressure = bmp.readPressure() / 100.0F;  // hPa\n  float altitude = bmp.readAltitude(1013.25);    // sea level hPa\n  \n  Serial.printf(\"Temp: %.1f°C, Pressure: %.1f hPa, Alt: %.1f m\\n\",\n                temp, pressure, altitude);\n  delay(2000);\n}\n```"},
    {"q": "How do I use a rotary encoder with Arduino?", "a": "<|thinking|>\nRotary encoder:\n1. Two phase outputs (A, B)\n2. Direction from phase relationship\n3. Interrupt for accuracy\n4. Optional button (SW)\n<|/thinking|>\n\n```cpp\n#define CLK 2  // Interrupt pin\n#define DT 3\n#define SW 4\n\nvolatile int counter = 0;\nvolatile bool buttonPressed = false;\nint lastCLK;\n\nvoid IRAM_ATTR readEncoder() {\n  int clk = digitalRead(CLK);\n  int dt = digitalRead(DT);\n  \n  if (clk != lastCLK && clk == LOW) {\n    if (dt != clk) {\n      counter++;  // Clockwise\n    } else {\n      counter--;  // Counter-clockwise\n    }\n  }\n  lastCLK = clk;\n}\n\nvoid IRAM_ATTR buttonISR() {\n  buttonPressed = true;\n}\n\nvoid setup() {\n  pinMode(CLK, INPUT_PULLUP);\n  pinMode(DT, INPUT_PULLUP);\n  pinMode(SW, INPUT_PULLUP);\n  \n  lastCLK = digitalRead(CLK);\n  attachInterrupt(digitalPinToInterrupt(CLK), readEncoder, CHANGE);\n  attachInterrupt(digitalPinToInterrupt(SW), buttonISR, FALLING);\n}\n\nvoid loop() {\n  static int lastCounter = 0;\n  if (counter != lastCounter) {\n    Serial.printf(\"Position: %d\\n\", counter);\n    lastCounter = counter;\n  }\n  if (buttonPressed) {\n    buttonPressed = false;\n    counter = 0;\n    Serial.println(\"Reset!\");\n  }\n}\n```"},
    {"q": "How do I read a GPS module with Arduino?", "a": "<|thinking|>\nGPS reading:\n1. Serial connection (9600 baud typical)\n2. Parse NMEA sentences\n3. TinyGPS++ library recommended\n4. Needs satellite lock (~30s first fix)\n<|/thinking|>\n\n```cpp\n#include <TinyGPS++.h>\n#include <SoftwareSerial.h>  // Or HardwareSerial\n\nTinyGPSPlus gps;\nSoftwareSerial gpsSerial(4, 3);  // RX, TX\n\nvoid setup() {\n  Serial.begin(115200);\n  gpsSerial.begin(9600);\n  Serial.println(\"Waiting for GPS fix...\");\n}\n\nvoid loop() {\n  while (gpsSerial.available() > 0) {\n    if (gps.encode(gpsSerial.read())) {\n      if (gps.location.isValid()) {\n        Serial.printf(\"Lat: %.6f, Lng: %.6f\\n\",\n                      gps.location.lat(), gps.location.lng());\n        Serial.printf(\"Altitude: %.1f m\\n\", gps.altitude.meters());\n        Serial.printf(\"Speed: %.1f km/h\\n\", gps.speed.kmph());\n        Serial.printf(\"Satellites: %d\\n\", gps.satellites.value());\n        Serial.printf(\"Time: %02d:%02d:%02d\\n\",\n                      gps.time.hour(), gps.time.minute(), gps.time.second());\n      }\n    }\n  }\n}\n```"},
    {"q": "How do I drive a stepper motor with AccelStepper?", "a": "<|thinking|>\nStepper with AccelStepper:\n1. Supports acceleration/deceleration\n2. Multiple driver types\n3. Non-blocking operation\n4. Position and speed control\n<|/thinking|>\n\n```cpp\n#include <AccelStepper.h>\n\n// Define motor connections (STEP, DIR for driver board)\n#define STEP_PIN 2\n#define DIR_PIN 3\n\nAccelStepper stepper(AccelStepper::DRIVER, STEP_PIN, DIR_PIN);\n\nvoid setup() {\n  stepper.setMaxSpeed(1000);      // Steps per second\n  stepper.setAcceleration(500);   // Steps per second^2\n}\n\nvoid loop() {\n  // Move to absolute position\n  stepper.moveTo(2000);  // 2000 steps (1 revolution at 200 steps/rev)\n  \n  while (stepper.distanceToGo() != 0) {\n    stepper.run();  // Must be called frequently\n  }\n  \n  delay(1000);\n  \n  // Move back\n  stepper.moveTo(0);\n  while (stepper.distanceToGo() != 0) {\n    stepper.run();\n  }\n  \n  delay(1000);\n}\n```\n\nFor smooth motion, call stepper.run() in loop without blocking delays."},
    {"q": "How do I measure distance with ultrasonic sensor (HC-SR04)?", "a": "<|thinking|>\nHC-SR04 ultrasonic:\n1. Trigger pulse starts measurement\n2. Echo pulse duration = distance\n3. Speed of sound calculation\n4. 2cm - 400cm range\n<|/thinking|>\n\n```cpp\n#define TRIG_PIN 5\n#define ECHO_PIN 18\n\nfloat measureDistance() {\n  // Clear trigger\n  digitalWrite(TRIG_PIN, LOW);\n  delayMicroseconds(2);\n  \n  // 10µs trigger pulse\n  digitalWrite(TRIG_PIN, HIGH);\n  delayMicroseconds(10);\n  digitalWrite(TRIG_PIN, LOW);\n  \n  // Measure echo pulse duration\n  long duration = pulseIn(ECHO_PIN, HIGH, 30000);  // 30ms timeout\n  \n  if (duration == 0) return -1;  // No echo\n  \n  // Calculate distance: duration/2 * speed of sound (0.0343 cm/µs)\n  float distance = (duration / 2.0) * 0.0343;\n  \n  return distance;\n}\n\nvoid setup() {\n  Serial.begin(115200);\n  pinMode(TRIG_PIN, OUTPUT);\n  pinMode(ECHO_PIN, INPUT);\n}\n\nvoid loop() {\n  float dist = measureDistance();\n  if (dist > 0) {\n    Serial.printf(\"Distance: %.1f cm\\n\", dist);\n  } else {\n    Serial.println(\"Out of range\");\n  }\n  delay(100);\n}\n```"},
    {"q": "How do I use an OLED display with Arduino?", "a": "<|thinking|>\nOLED display (SSD1306):\n1. I2C connection (SDA, SCL)\n2. Adafruit SSD1306 library\n3. GFX library for graphics\n4. Address usually 0x3C\n<|/thinking|>\n\n```cpp\n#include <Wire.h>\n#include <Adafruit_GFX.h>\n#include <Adafruit_SSD1306.h>\n\n#define SCREEN_WIDTH 128\n#define SCREEN_HEIGHT 64\n#define OLED_ADDR 0x3C\n\nAdafruit_SSD1306 display(SCREEN_WIDTH, SCREEN_HEIGHT, &Wire, -1);\n\nvoid setup() {\n  if (!display.begin(SSD1306_SWITCHCAPVCC, OLED_ADDR)) {\n    Serial.println(\"SSD1306 failed!\");\n    while (1);\n  }\n  \n  display.clearDisplay();\n  display.setTextSize(1);\n  display.setTextColor(SSD1306_WHITE);\n}\n\nvoid showSensorData(float temp, float humidity) {\n  display.clearDisplay();\n  \n  display.setTextSize(2);\n  display.setCursor(0, 0);\n  display.printf(\"%.1fC\", temp);\n  \n  display.setTextSize(1);\n  display.setCursor(0, 20);\n  display.printf(\"Humidity: %.1f%%\", humidity);\n  \n  // Draw a bar graph\n  int barWidth = map(humidity, 0, 100, 0, SCREEN_WIDTH);\n  display.fillRect(0, 40, barWidth, 10, SSD1306_WHITE);\n  display.drawRect(0, 40, SCREEN_WIDTH, 10, SSD1306_WHITE);\n  \n  display.display();\n}\n```"},
    {"q": "How do I interface with an SD card on ESP32?", "a": "<|thinking|>\nSD card on ESP32:\n1. SPI interface\n2. FAT32 format\n3. Data logging use case\n4. Watch for write timing\n<|/thinking|>\n\n```cpp\n#include <SPI.h>\n#include <SD.h>\n\n#define SD_CS 5  // Chip select pin\n\nvoid setup() {\n  Serial.begin(115200);\n  \n  if (!SD.begin(SD_CS)) {\n    Serial.println(\"SD card failed!\");\n    return;\n  }\n  \n  Serial.printf(\"Card size: %llu MB\\n\", SD.cardSize() / (1024 * 1024));\n}\n\nvoid logData(float temp, float humidity) {\n  File file = SD.open(\"/datalog.csv\", FILE_APPEND);\n  \n  if (file) {\n    file.printf(\"%lu,%.2f,%.2f\\n\", millis(), temp, humidity);\n    file.close();\n    Serial.println(\"Logged\");\n  } else {\n    Serial.println(\"Failed to open file\");\n  }\n}\n\nvoid readLog() {\n  File file = SD.open(\"/datalog.csv\");\n  if (file) {\n    while (file.available()) {\n      Serial.write(file.read());\n    }\n    file.close();\n  }\n}\n\nvoid loop() {\n  float temp = readTemp();\n  float hum = readHumidity();\n  logData(temp, hum);\n  delay(60000);  // Log every minute\n}\n```"},
]

